module sovryn_pan_stem_npu_array_v4_seed_g_issue(
  input wire clk,
  input wire rst_n,
  input wire advance_tick,
  output reg [15:0] current_instruction,
  output wire step_valid
);
  assign step_valid = advance_tick;

  // 16-bit instruction memory (256 depth for now, matching the tile local phase space)
  reg [15:0] instr_memory [0:255];
  reg [7:0] pc; // Program Counter

  initial begin
    // Use the Bitstream file generated by the Spatial Compiler
    $readmemh("outputs/runtime/npu-v4-hello-world/v4_seed_g_program.hex", instr_memory);
  end

  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      pc <= 8'd0;
      current_instruction <= 16'd0;
    end else if (advance_tick) begin
      current_instruction <= instr_memory[pc];
      pc <= pc + 8'd1;
    end
  end
endmodule
